// Pure filesystem-level management of enabled example extensions.
// Enable = copy the example from <examplesDir>/<key> to <extDir>/<key> (real file/dir,
//   so pi's auto-discovery picks it up after /reload).
// Disable = remove <extDir>/<key>, but ONLY if it's in our managed state file
//   (never touch baz/, orchestrator/, examples/, or user-added files).
// Conflict check = no two members of the same singleton `group` active at once.
//
// No pi imports here -> unit-testable in isolation.

import { cpSync, rmSync, existsSync, readFileSync, writeFileSync, mkdirSync } from "node:fs";
import { join } from "node:path";
import { CATALOG, PROFILES, type CatalogEntry } from "./catalog.ts";

export type Result = {
  ok: boolean;
  message: string;
  changed: boolean;
  enabled?: string[];
  conflicts?: string[];
};

display.text:
// Pure filesystem-level management of enabled example extensions.
// Enable = copy the example from <examplesDir>/<key> to <extDir>/<key> (real file/dir,
//   so pi's auto-discovery picks it up after /reload).
// Disable = remove <extDir>/<key>, but ONLY if it's in our managed state file
//   (never touch baz/, orchestrator/, examples/, or user-added files).
// Conflict check = no two members of the same singleton `group` active at once.
//
// No pi imports here -> unit-testable in isolation.

import { cpSync, rmSync, existsSync, readFileSync, writeFileSync, mkdirSync } from "node:fs";
import { join } from "node:path";
import { CATALOG, PROFILES, type CatalogEntry } from "./catalog.ts";

export type Result = {
  ok: boolean;
  message: string;
  changed: boolean;
  enabled?: string[];
  conflicts?: string[];
};

export function createManager(opts: { extDir: string; examplesDir: string; stateFile: string }) {
  const { extDir, examplesDir, stateFile } = opts;

  const byKey = new Map<string, CatalogEntry>();
  for (const e of CATALOG) byKey.set(e.key, e);

  function readState(): string[] {
    try {
      const v = JSON.parse(readFileSync(stateFile, "utf8"));
      return Array.isArray(v) ? v as string[] : [];
    } catch {
      return [];
    }
  }

  function writeState(names: string[]) {
    mkdirSync(extDir, { recursive: true });
    writeFileSync(stateFile, JSON.stringify([...new Set(names)].sort(), null, 2));
  }

  // All example keys present on disk (managed by us OR added manually), plus any
  // managed keys we believe are enabled (even if a scan would miss them).
  function presentKeys(): Set<string> {
    const out = new Set<string>();
    for (const k of byKey.keys()) if (existsSync(join(extDir, k))) out.add(k);
    for (const k of readState()) if (existsSync(join(extDir, k))) out.add(k);
    return out;
  }

  function conflictsFor(key: string): string[] {
    const e = byKey.get(key);
    if (!e?.group) return [];
    const present = presentKeys();
    const others: string[] = [];
    for (const k of present) {
      if (k === key) continue;
      const oe = byKey.get(k);
      if (oe?.group === e.group) others.push(k);
    }
    return others;
  }

  function enableKey(key: string): Result {
    const src = join(examplesDir, key);
    const dst = join(extDir, key);
    if (!existsSync(src)) {
      return { ok: false, message: `No such example: '${key}' (not found under ${examplesDir}). Try action=list.`, changed: false };
    }
    if (existsSync(dst)) {
      // Already present (managed or manual). Make sure it's tracked.
      const st = readState();
      if (!st.includes(key)) { st.push(key); writeState(st); }
      return { ok: true, message: `'${key}' is already enabled`, changed: false };
    }
    const e = byKey.get(key);
    if (e?.requiresSetup) {
      return { ok: false, message: `'${key}' requires setup (${e.note ?? "external dependencies/config"}). Install/configure it, then enable manually.`, changed: false };
    }
    const conflicts = conflictsFor(key);
    if (conflicts.length) {
      return {
        ok: false,
        message: `Conflict: '${key}' is in singleton group '${e?.group}', already held by ${conflicts.join(", ")}. Disable that first (orchestrate disable) or pick a different one.`,
        changed: false,
        conflicts,
      };
    }
    try {
      cpSync(src, dst, { recursive: true });
    } catch (err) {
      return { ok: false, message: `Failed to copy '${key}': ${(err as Error).message}`, changed: false };
    }
    const st = readState();
    if (!st.includes(key)) { st.push(key); writeState(st); }
    return { ok: true, message: `Enabled '${key}'${e?.note ? ` (${e.note})` : ""}`, changed: true, enabled: [key] };
  }

  function disableKey(key: string): Result {
    const dst = join(extDir, key);
    const st = readState();
    if (!st.includes(key)) {
      if (existsSync(dst)) {
        return { ok: false, message: `'${key}' is present but not managed by orchestrator. Remove it manually if desired.`, changed: false };
      }
      return { ok: true, message: `'${key}' is not enabled`, changed: false };
    }
    try {
      rmSync(dst, { recursive: true, force: true });
    } catch (err) {
      return { ok: false, message: `Failed to remove '${key}': ${(err as Error).message}`, changed: false };
    }
    writeState(st.filter((k) => k !== key));
    return { ok: true, message: `Disabled '${key}'`, changed: true };
  }

  function enableProfile(profile: string): Result {
    const p = PROFILES[profile];
    if (!p) {
      return { ok: false, message: `No such profile: '${profile}'. Available: ${Object.keys(PROFILES).join(", ")}`, changed: false };
    }
    const enabled: string[] = [];
    const skipped: string[] = [];
    const failed: string[] = [];
    for (const k of p.keys) {
      const r = enableKey(k);
      if (r.changed) enabled.push(k);
      else if (r.ok) skipped.push(k);
      else failed.push(`${k}: ${r.message}`);
    }
    const parts: string[] = [];
    if (enabled.length) parts.push(`Enabled: ${enabled.join(", ")}`);
    if (skipped.length) parts.push(`Already active: ${skipped.join(", ")}`);
    if (failed.length) parts.push(`Skipped: ${failed.join("; ")}`);
    return {
      ok: failed.length === 0,
      message: `Profile '${profile}' — ${p.desc}\n${parts.join(" | ")}`,
      changed: enabled.length > 0,
      enabled,
    };
  }

  function disableProfile(profile: string): Result {
    const p = PROFILES[profile];
    if (!p) return { ok: false, message: `No such profile: '${profile}'`, changed: false };
    const disabled: string[] = [];
    for (const k of p.keys) {
      const r = disableKey(k);
      if (r.changed) disabled.push(k);
    }
    return {
      ok: true,
      message: `Disabled profile '${profile}': ${disabled.length ? disabled.join(", ") : "nothing to disable"}`,
      changed: disabled.length > 0,
    };
  }

  function reset(): Result {
    const st = readState();
    const removed: string[] = [];
    for (const k of st) {
      try {
        rmSync(join(extDir, k), { recursive: true, force: true });
        removed.push(k);
      } catch {
        /* ignore */
      }
    }
    writeState([]);
    return {
      ok: true,
      message: `Reset: removed ${removed.length ? removed.join(", ") : "nothing (no managed extensions)"}`,
      changed: removed.length > 0,
    };
  }

  function status(): string {
    const managed = readState().slice().sort();
    const present = [...presentKeys()].sort();
    const groups = new Map<string, string[]>();
    for (const k of present) {
      const e = byKey.get(k);
      if (e?.group) groups.set(e.group, [...(groups.get(e.group) ?? []), k]);
    }
    const conflictWarnings: string[] = [];
    for (const [g, ks] of groups) if (ks.length > 1) conflictWarnings.push(`group '${g}' has multiple active: ${ks.join(", ")}`);
    const lines: string[] = [];
    lines.push(`Managed by orchestrator: ${managed.length ? managed.join(", ") : "(none)"}`);
    lines.push(`Present on disk: ${present.length ? present.join(", ") : "(none)"}`);
    if (conflictWarnings.length) lines.push(`CONFLICTS: ${conflictWarnings.join("; ")}`);
    lines.push(`Profiles: ${Object.keys(PROFILES).join(", ")}`);
    return lines.join("\n");
  }

  return { readState, presentKeys, conflictsFor, enableKey, disableKey, enableProfile, disableProfile, reset, status, byKey, PROFILES };
}

