export const PROFILES: Record<string, Profile> = {
  safe: {
    desc: "Safety gates: confirm dangerous ops, protect sensitive paths, guard dirty repos",
    when: "before destructive commands (rm -rf, sudo, git push --force, dropping tables) or work in sensitive repos",
    keys: ["permission-gate.ts", "protected-paths.ts", "confirm-destructive.ts", "dirty-repo-guard.ts"],
  },
  git: {
    desc: "Git workflow: stash checkpoints each turn, guard dirty repos, auto-commit on exit",
    when: "working inside a git repository (look for .git)",
    keys: ["git-checkpoint.ts", "dirty-repo-guard.ts", "auto-commit-on-exit.ts"],
  },
  ui: {
    desc: "Polished UI: custom header & footer, titlebar spinner, desktop notifications on finish",
    when: "the user asks for a richer, more informative interface",
    keys: ["custom-header.ts", "custom-footer.ts", "titlebar-spinner.ts", "notify.ts"],
  },
  focus: {
    desc: "Distraction-free: minimal tool rendering, hidden thinking blocks, custom working indicator",
    when: "the user asks for a minimal, focused interface for deep work",
    keys: ["minimal-mode.ts", "hidden-thinking-label.ts", "working-indicator.ts"],
  },
  play: {
    desc: "Games while you wait (snake, space invaders, tic-tac-toe) + desktop notifications",
    when: "a task will take a while and the user is waiting",
    keys: ["snake.ts", "space-invaders.ts", "tic-tac-toe.ts", "notify.ts"],
  },
  review: {
    desc: "Code review & navigation: /summarize, bookmarks for /tree, auto-compact at 100k tokens",
    when: "doing a code review or navigating a long session",
    keys: ["summarize.ts", "bookmark.ts", "trigger-compact.ts"],
  },
  power: {
    desc: "Power-user session tools: presets, /tools toggle, /handoff, session naming",
    when: "the user is a power user juggling models, tools, and sessions",
    keys: ["preset.ts", "tools.ts", "handoff.ts", "session-name.ts"],
  },
  plan: {
    desc: "Plan mode: read-only exploration with /plan, step tracking, write tools disabled",
    when: "exploring a codebase before making changes",
    keys: ["plan-mode"],
  },
  context: {
    desc: "Extra system-prompt context: load .claude/rules, context-aware tool guidance",
    when: "the project has .claude/rules or needs extra context injected",
    keys: ["claude-rules.ts", "prompt-customizer.ts"],
  },
};

