  { key: "git-merge-and-resolve.ts", desc: "Fetch, merge, and resolve conflicts on agent_end", note: "Auto-runs at end of turn" },
  // --- UI (singletons) ---
  { key: "custom-header.ts", desc: "Custom startup header", group: "header" },
  { key: "custom-footer.ts", desc: "Custom footer (git branch + token stats)", group: "footer" },
  { key: "status-line.ts", desc: "Turn progress in footer status", group: "footer" },
  { key: "model-status.ts", desc: "Model changes in footer status", group: "footer" },
  { key: "titlebar-spinner.ts", desc: "Braille spinner in terminal title while working", group: "titlebar" },
  { key: "minimal-mode.ts", desc: "Minimal built-in tool rendering (no output when collapsed)", group: "tool-render" },
  { key: "built-in-tool-renderer.ts", desc: "Compact custom rendering for built-in tools", group: "tool-render" },
  { key: "hidden-thinking-label.ts", desc: "Customize the collapsed thinking label", group: "thinking-label" },
  { key: "working-indicator.ts", desc: "Custom streaming working indicator", group: "working-indicator" },
  { key: "modal-editor.ts", desc: "Vim-like modal editor", group: "editor" },
  { key: "rainbow-editor.ts", desc: "Animated rainbow editor effect", group: "editor" },
  { key: "pirate.ts", desc: "Modify system prompt persona per turn (pirate)", group: "persona" },
  { key: "custom-compaction.ts", desc: "Custom compaction summary", group: "compaction-handler" },
  { key: "tool-override.ts", desc: "Override built-in read tool (logging/access control)", group: "tool-read-override", note: "Replaces built-in read tool" },
  // --- games ---
  { key: "snake.ts", desc: "Snake game" },
  { key: "space-invaders.ts", desc: "Space Invaders game" },
  { key: "tic-tac-toe.ts", desc: "Tic-tac-toe vs the agent" },
  { key: "doom-overlay", desc: "DOOM as an overlay (35 FPS)", requiresSetup: true, note: "Needs the DOOM binary/assets" },
  // --- review / sessions ---
  { key: "summarize.ts", desc: "/summarize conversation with a model and show in transient UI", note: "Calls a model" },
  { key: "bookmark.ts", desc: "Bookmark entries with labels for /tree navigation" },
  { key: "trigger-compact.ts", desc: "Auto-compact at 100k tokens + /trigger-compact command" },
  { key: "preset.ts", desc: "Named presets (model, thinking, tools, instructions) via --preset / /preset" },
  { key: "tools.ts", desc: "Interactive /tools command to toggle tools" },
  { key: "handoff.ts", desc: "/handoff to a new focused session" },
  { key: "session-name.ts", desc: "Name sessions for the session selector" },
  { key: "plan-mode", desc: "Plan mode: read-only exploration, /plan, step tracking" },
  // --- context ---
  { key: "claude-rules.ts", desc: "Scan .claude/rules/ and list rules in system prompt" },
  { key: "prompt-customizer.ts", desc: "Context-aware tool guidance via systemPromptOptions" },
  { key: "system-prompt-header.ts", desc: "Display system prompt info on agent_start" },
  // --- misc useful ---
