display.text:
/**
 * baz-guardrails — reusable guardrail snippets function.
 * Provides: baz_snippet tool (load a snippet), /snippet command, and the
 * snippet library in ./snippets/*.md.
 */

import { existsSync, readdirSync, readFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import { StringEnum } from "@earendil-works/pi-ai";
import { Type } from "typebox";
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";

const baseDir = dirname(fileURLToPath(import.meta.url));
const SNIPPET_DIR = join(baseDir, "snippets");

function listSnippets(): string[] {
  try {
    return readdirSync(SNIPPET_DIR).filter((f) => f.endsWith(".md")).map((f) => f.slice(0, -3)).sort();
  } catch {
    return [];
  }
}

function readSnippet(name: string): string | null {
  try {
    const f = join(SNIPPET_DIR, `${name}.md`);
    if (!existsSync(f)) return null;
    return readFileSync(f, "utf-8");
  } catch {
    return null;
  }
}

export default function bazGuardrails(pi: ExtensionAPI) {
  const snippets = listSnippets();

  pi.on("before_agent_start", async (event) => {
    const snipList = snippets.map((s) => `  - ${s}`).join("\n") || "  (none found)";
    const block = `

## BAZ guardrails

Reusable guardrail snippets. Load with the \`baz_snippet\` tool or apply to the current task with \`/snippet [name]\`.
${snipList}
`;
    return { systemPrompt: event.systemPrompt + block };
  });

  const snippetNameSchema =
    snippets.length > 0
      ? StringEnum(snippets, { description: "Snippet name (filename without .md)" })
      : Type.String({ description: "Snippet name (filename without .md)" });

  pi.registerTool({
    name: "baz_snippet",
    label: "BAZ Snippet",
    description:
      "Load a reusable BAZ guardrail snippet and return its content. Use to apply guardrails (security-checklist, careful, testing-requirements, style-guide, error-handling, performance-tips, tdd, etc.).",
    promptSnippet: "Load a BAZ guardrail snippet by name",
    promptGuidelines: [
      "Use baz_snippet to load guardrails (e.g. security-checklist, careful) when a task would benefit, rather than restating rules from memory.",
    ],
    parameters: Type.Object({ name: snippetNameSchema }),
    async execute(_id, params, _signal, _onUpdate, _ctx) {
      const content = readSnippet(params.name);
      if (content == null) {
        return {
          content: [{ type: "text", text: `Snippet '${params.name}' not found. Available: ${snippets.join(", ") || "(none)"}` }],
          details: { found: false },
          isError: true,
        };
      }
      return { content: [{ type: "text", text: content }], details: { found: true } };
    },
  });

  async function runSnippet(args: string, ctx: { hasUI: boolean; ui: any }) {
    let name = args.trim();
    if (!name) {
      if (!ctx.hasUI || snippets.length === 0) {
        ctx.ui?.notify?.(`BAZ snippets: ${snippets.join(", ") || "(none)"}`, "info");
        return;
      }
      name = (await ctx.ui.select("BAZ snippet to apply", snippets)) ?? "";
    }
    if (!name) return;
    const content = readSnippet(name);
    if (!content) {
      ctx.ui?.notify?.(`BAZ snippet '${name}' not found`, "warning");
      return;
    }
    pi.sendUserMessage(
      [{ type: "text", text: `Apply this BAZ guardrail snippet ('${name}') to the current task:\n\n${content}` }],
      { triggerTurn: true },
    );
  }

  pi.registerCommand("snippet", {
    description: "BAZ: apply a guardrail snippet to the current task",
    getArgumentCompletions: (prefix: string) => {
      const f = snippets.filter((s) => s.startsWith(prefix));
      return f.length ? f.map((s) => ({ value: s, label: s })) : null;
    },
    handler: async (args, ctx) => runSnippet(args, ctx),
  });
}

